class RandomUtils {
    /**
    * Convert mode string to mode id
    * @param {'standard' | 'taiko' | 'ctb' | 'mania'} mode 
    * @private
    */
    static parseMode(mode) {
       switch(mode) {
           case 'standard':
               return 0;
               break;
           case 'taiko':
               return 1;
               break;
           case 'ctb':
               return 2;
               break;
           case 'mania':
               return 3;
               break;
           default:
               throw TypeError(mode + ' is not a valid mode');
       }
   }

    static parseModeID(ID) {
        switch(Number(ID)) {
            case 0:
                return 'standard';
                break;
            case 1:
                return 'taiko';
                break;
            case 2:
                return 'ctb';
                break;
            case 3:
                return 'mania';
                break;

        }
   }

   static sleep(ms) {
       return new Promise(resolve => setTimeout(resolve, ms));
   }
}

module.exports = RandomUtils;